Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it hosts your app in-memory and gives you an `HttpClient` that talks to it without opening a real port.

```csharp
// MyMcpTests.cs
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }
}
```

**Key points:**

- **No real port** — `WebApplicationFactory` uses an in-process `TestServer`.
- **Full pipeline** — middleware, routing, DI, and serialization all run exactly as in production.
- **Override services** — use `.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in test doubles (e.g., mock databases).
- **SSE/streaming** — for Streamable HTTP (`Accept: text/event-stream`), use `SendAsync` with `HttpCompletionOption.ResponseHeadersRead` and read the response stream line-by-line.
- Make sure your test project references `Microsoft.AspNetCore.Mvc.Testing` and your server project exposes a `Program` class (top-level statements work — just add `public partial class Program { }` at the bottom of `Program.cs` if needed).
